INSERT INTO order_items (
    oid, cid, pid, category, title, author, quantity, price, period, size, thumbnail, 
    order_status, deposit, finish_type, 
    retouch_enabled, retouch_types, retouch_note
) VALUES (
    #{oid}, #{item.cid}, #{item.pid}, #{item.category}, #{item.title}, #{item.author}, #{item.quantity}, #{item.price}, 
    #{item.period}, #{item.size}, #{item.thumbnail}, #{item.orderStatus}, #{item.deposit}, #{item.finishType},
    COALESCE(#{item.retouchEnabled}, 0), #{item.retouchTypes}, #{item.retouchNote}
)

